import{_ as a,o as e,c as r,a9 as p}from"./chunks/framework.D4xYp1Zt.js";const o="/images/baby/01_water-broke.png",n="/images/baby/02_emoji-150x150.png",s="/images/baby/03_birth-1.png",i="/images/baby/04_birth-2.png",h="/images/baby/05_birth-3.png",l="/images/baby/06_fetus-baby-1.png",b="/images/baby/07_fetus-baby-2.png",m="/images/baby/08_pieces.png",_="/images/baby/09_heads-v2.png",c="/images/baby/10_agony.png",g="/images/baby/11_little-man.png",f="/images/baby/12_one-sided.png",u="/images/baby/13_sleep-graph-1.png",w="/images/baby/14_sleep-graph-2.png",d="/images/baby/15_sleep-graph-3-750x242.png",y="/images/baby/16.1_friends.png",k="/images/baby/16.2_friends.png",q="/images/baby/16.3_friends.png",T="/images/baby/16.4_friends.png",x="/images/baby/16.5_friends.png",P="/images/baby/17_stars.png",A="/images/baby/pinit_fg_en_rect_gray_20.png",C=JSON.parse('{"title":"10 Thoughts from the Fourth Trimester","description":"","frontmatter":{"title":"10 Thoughts from the Fourth Trimester","titleZh":"产后第四孕期的十点感悟","date":"2023-05-23T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2023/05/baby.html","slug":"baby"},"headers":[],"relativePath":"posts/baby.md","filePath":"posts/baby.md","lastUpdated":1782886257000}'),B={name:"posts/baby.md"};function S(v,t,W,I,F,M){return e(),r("div",null,[...t[0]||(t[0]=[p('<h1 id="产后第四孕期的十点感悟-·-10-thoughts-from-the-fourth-trimester" tabindex="-1">产后第四孕期的十点感悟 · 10 Thoughts from the Fourth Trimester <a class="header-anchor" href="#产后第四孕期的十点感悟-·-10-thoughts-from-the-fourth-trimester" aria-label="Permalink to &quot;产后第四孕期的十点感悟 · 10 Thoughts from the Fourth Trimester&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2023/05/baby.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2023/05/baby.html</a> · 2023-05-23</p></blockquote><p>二月份的时候,我写了一篇<a href="https://waitbutwhy.com/2023/02/last-six-years.html" target="_blank" rel="noreferrer">博文</a>,讲我即将出版的<a href="https://waitbutwhy.com/whatsourproblem" target="_blank" rel="noreferrer">新书</a>,里面有一张<a href="https://waitbutwhy.com/wp-content/uploads/2023/05/00_days.png" target="_blank" rel="noreferrer">时间线大图</a>。就在新书发布两周后,我的第一个宝宝就要出生了。我会先给新书做宣传,喘口气,然后开启新的冒险。</p><p>谢天谢地,幸好中间还有这关键的两周。</p><p>新书发布前一晚(不出所料)是一场慌乱的通宵,我最终在连续清醒 40 小时后倒头就睡,精疲力竭却心满意足。我们做到了。书上线了。一切结束了。明天早上醒来,这个项目终于不会再压在我头上。天空会是蓝的。我终于自由了。</p><p>我睡到接近中午才醒,感受了 3 秒的安宁,然后打开手机,看到我妻子发来的三条短信:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/01_water-broke.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>嗯?</p><p>我知道破水是什么。但我不知道它意味着什么。是宝宝现在就要出来了?还是这只是我听说过的那种假警报,宝宝还得再等几周?或者……有没有可能她只是尿裤子了,自己误诊了?</p><p>一通迅雷不及掩耳的谷歌搜索之后,有一件事很清楚:我们得去医院。现在就去。</p><p>开车去医院的路上感觉怪怪的。我脑子里的画面本来是我英勇地载着一个尖叫着阵痛的妻子飞车前往医院,但现实是我旁边坐着一个非常正常的妻子,我非常正常地开着车。除了她新出现的漏水情况,一切都和昨天没什么两样。我们今天怎么可能真的就要有孩子了。对吧?</p><p>到医院后,助理医师做了评估——是的,她确实破水了,是的,为了避免感染,宝宝必须现在就出来。两小时和 12 个被取消的新书宣传播客之后,我们进了产房,我那还没开始阵痛的妻子据说会在今天晚些时候把一个宝宝生出来。</p><p>再一次,预期与现实严重不符。我想象中第一个孩子出生的那天应该是无比慌乱、情绪爆炸、极度紧张的。但此时此刻,我们正坐在那儿吃动物饼干和软糖(从「产程中可食用的零食袋」里拿的),就跟平常日子一样闲聊、打发时间。</p><p>我妻子身上连了一堆管子和机器,计划是看她的破水会不会自然引发宫缩,但过了几个小时,啥也没发生。最后,护士进来,把一种叫催产素 (Pitocin) 的神奇小药水倒进了她的输液袋里。</p><p>于是事情开始发生了。</p><p>宫缩开始了,我妻子形容那是「非常严重的痛经」,这让我 0% 地理解了那到底是什么感觉。接下来几个小时,宫缩越来越剧烈。我被迅速分配到「什么也别说什么也别做」的角色,在宫缩发作时,我就尴尬地坐在一边看着,脸上挂着这种表情:</p><p><img src="'+n+'" alt=""></p><p>她的无痛计划大概是「肯定要打,但先硬扛一会儿」,在经历了一次特别可怕的宫缩之后,她决定收工,无痛团队进来做他们的事。45 分钟后,我们又回到了那个「我知道今天是我们第一个孩子出生的日子但真的完全感觉不像」的状态,像平时一样聊天、闲逛。又过了几个小时,一个护士进来检查了宫口开的情况,说:「好,咱们开始吧!」</p><p>再一次,和我想象的完全不一样。我以为会有一大群医生护士忙成一团,而我站在旁边某个角落。结果,就是我和这个护士,一人抓一条腿。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/03_birth-1.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>游戏是这么玩的:宫缩开始时,我们各抓一条腿,她连续用力推 10 秒,推三次。然后大家放松一下,闲聊几分钟,直到下一次宫缩。如此循环。</p><p>这样来了几轮之后,很明显这招不管用。什么都没出来。但我们还是继续试。</p><p>然后我看到了。</p><p>一张令人不安的黏糊糊煎饼的边缘。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/04_birth-2.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>我问那个令人不安的黏糊糊煎饼边缘是什么,护士告诉我那是我女儿。</p><p>嗯哼。</p><p>这样又持续了一阵子。我们推一轮,那个令人不安的煎饼东西会出来一厘米然后又缩回去,每一轮会多出来几毫米。这个策略越来越感觉根本没进展,这时护士突然说:「好,咱们把宝宝生出来吧!」</p><p>她打了个电话,几分钟后一群人走了进来,包括我们那天见到的第一个医生。下一次宫缩来了,我抓着腿,我老婆用力推,然后在我人生中最超现实的一刻,我盯着一个尖叫的小外星人。</p><h2 id="" tabindex="-1"><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/05_birth-3.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![](/images/baby/05_birth-3.png)](https://waitbutwhy.com/wp-content/uploads/2023/05/05_birth-3.png)&quot;">​</a></h2><p>那是 3 个月前的事了。从那以后我有了很多想法。这里是其中的 10 个:</p><h3 id="_1-新生儿不是婴儿" tabindex="-1">1) 新生儿不是婴儿 <a class="header-anchor" href="#_1-新生儿不是婴儿" aria-label="Permalink to &quot;1) 新生儿不是婴儿&quot;">​</a></h3><p>我以为会是这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/06_fetus-baby-1.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>但实际上是这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/07_fetus-baby-2.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>新生儿不是宝宝。宝宝是可爱的、圆滚滚的、能看见东西、有意识、正常——而新生儿一样都不占。它是一个诡异的人类幼虫,<a href="https://www.instagram.com/reel/CqWS89MAE-5/?igshid=YmMyMTA2M2Y%3D" target="_blank" rel="noreferrer">行为超级怪异</a>,要是能待在子宫里它绝对不会出来。问题是,人类开始直立行走后,骨盆变小了;人类变聪明后,脑袋又变大了。所以进化只能想点花招。它的解决方案:所有人类婴儿都是早产儿,趁着还小到能穿过人类骨盆的时候就得出来。当胎儿的最后几个月挪到子宫外面完成,大家自个儿凑合吧。这件事在我女儿出生的第一个月里变得极其明显。她就是一坨原始的人类本我 (id),完全没准备好登台亮相。谢天谢地,从那以后,一个宝宝逐渐在这团本我周围长了出来,现在她拥有了一个迷你版 390 磅 84 岁老太太的身材。<a href="#footnote-1-10203">1</a></p><h3 id="_2-准父母居然不需要经过什么强制培训-这事简直离谱" tabindex="-1">2) 准父母居然不需要经过什么强制培训,这事简直离谱 <a class="header-anchor" href="#_2-准父母居然不需要经过什么强制培训-这事简直离谱" aria-label="Permalink to &quot;2) 准父母居然不需要经过什么强制培训,这事简直离谱&quot;">​</a></h3><p>我要想开车,得先上驾校。我要想给别人提供医疗建议,得先上医学院。但我们生完孩子后,医院的态度基本上就是「别摇它,好了拜拜」。</p><p>我现在知道了一堆以前不知道的词。胎便 (Meconium)。趴卧时间 (Tummy time)。含乳 (Latching)。蹬自行车 (Bicycling)。襁褓 (Swaddle)。初乳 (Colostrum)。我知道宝宝每天应该喝多少盎司的奶、睡多少小时。我会婴儿心肺复苏和婴儿海姆立克急救法。我知道怎么诱导宝宝打嗝拉屎。我知道该给宝宝穿多暖。我知道宝宝洗澡水该是什么温度。我知道什么叫睡眠训练、什么时候开始比较合适。我知道你不能就那么把新生儿抱起来,你得把所有零件同时抱起来,不然零件会掉。</p><p><img src="'+m+'" alt=""></p><p><em>但我知道这些,只是因为我读了书、读了文章,而且我有幸有一些可以打电话问问题的人。</em> 而社会目前的方案就是指望/希望每一个新手父母都能做同样的事??显然应该有个类似强制性的四小时课程,每个准父母在真正开始负责一个新生儿之前都必须上。</p><p>结果,人们喜欢说什么「你自己会摸索出来的」、「跟着本能走就行」。你把这套逻辑套到开车上,人们大概<em>也</em>能摸索出来——但我们不那么干,因为那样太荒唐了。</p><h3 id="_3-婴儿的头巨大" tabindex="-1">3) 婴儿的头巨大* <a class="header-anchor" href="#_3-婴儿的头巨大" aria-label="Permalink to &quot;3) 婴儿的头巨大\\*&quot;">​</a></h3><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/09_heads-v2.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>*我做这张图本来是想强调婴儿的头有多大,但盯着右边那个大头男看了一会儿之后,我开始觉得他挺正常的,反而是那个正常头的男的突然看起来头小得离谱。所以我现在意识到,真正的重点其实是:婴儿的头才是正常的,我们其他人的头都是袖珍款。</p><h3 id="_4-婴儿的戏剧化程度令人发指" tabindex="-1">4) 婴儿的戏剧化程度令人发指 <a class="header-anchor" href="#_4-婴儿的戏剧化程度令人发指" aria-label="Permalink to &quot;4) 婴儿的戏剧化程度令人发指&quot;">​</a></h3><p>普通人饿了、累了、或者需要打嗝时,顶多有点烦躁。婴儿则是<em>莎士比亚级别的痛苦</em>。然后嗝一打出来,一秒钟之后他们就跟没事人一样:「嘿。」这行为简直疯了。</p><p>有那么一段时间,婴儿的情绪范围只在莎士比亚级痛苦到中性之间摆动,从不进入正面区间。中性就是新生儿的最佳状态。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/10_agony.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>大约六周以后,正面情绪开始出现,但他们依然会因为最微小的不便而暴跳如雷。<a href="#footnote-2-10203">2</a></p><p>顺便说一下,我知道这样不好但我忍不住——哭泣的婴儿很好笑。我老婆完全不同意我这个观点。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/11_little-man.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><h3 id="_5-父母与新生儿的关系极其单向" tabindex="-1">5) 父母与新生儿的关系极其单向 <a class="header-anchor" href="#_5-父母与新生儿的关系极其单向" aria-label="Permalink to &quot;5) 父母与新生儿的关系极其单向&quot;">​</a></h3><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/12_one-sided.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>这很奇怪——你对这个小人儿*怀有一堆强烈的感情,但这些感情根本没地方<em>释放</em>。我可以捏她的脸,但那样她会哭,我就成了虐待婴儿的人。在最初几周,你对宝宝的喜爱之情根本找不到令人满意的出口,这让人很郁闷。</p><p>另一个单向的事情是,你还得跟新生儿说话,尽管他们就是个无意识的胎儿——据说这有助于他们大脑发育。所以我的宝宝已经听过我下一本书大纲的好几个版本,听过我在听完一期播客后转述的亚述帝国兴衰史全集,还听过一份从 1990 年至今每一届世界大赛冠军的名单。婴儿从来没有表现出任何一丝被这些内容影响的迹象。</p><p>*话说回来,我一直以为父母之爱是最强烈的爱——那种索菲的抉择场景里,你的宝宝和配偶同时挂在悬崖边、你只能救一个的话,你会毫不犹豫地救宝宝。然而……嗯我还没到那个境界。我对这个小生物的爱到了畸形的程度,但截至目前,那种情况下我肯定救我老婆。抱歉了孩子。我相信「救老婆丢娃的 Tim」终有一天会进化成「救娃丢老婆的 Tim」,但看来这需要点时间。</p><h3 id="_6-婴儿把你的时间表搅得屎一样" tabindex="-1">6) <strong>婴儿把你的时间表搅得屎一样</strong> <a class="header-anchor" href="#_6-婴儿把你的时间表搅得屎一样" aria-label="Permalink to &quot;6) **婴儿把你的时间表搅得屎一样**&quot;">​</a></h3><p>明显的一点,我知道,但看看这个:<a href="#footnote2-1-10203">1</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/13_sleep-graph-1.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/14_sleep-graph-2.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/15_sleep-graph-3.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>这是三个不同婴儿的睡眠图,但它们有一个共同点:前几个月毫无规律可言,因为新生儿就是混蛋。</p><h3 id="_7-从数学上讲-你根本不可能知道自己的娃到底可不可爱" tabindex="-1">7) 从数学上讲,你根本不可能知道自己的娃到底可不可爱 <a class="header-anchor" href="#_7-从数学上讲-你根本不可能知道自己的娃到底可不可爱" aria-label="Permalink to &quot;7) 从数学上讲,你根本不可能知道自己的娃到底可不可爱&quot;">​</a></h3><p>我当然觉得我的娃可爱到不像话,但每个家长都这么觉得,所以这信息量为零。所有见过她本人或看过她照片的人都说她多可爱,但不管她长什么样人家都会这么说——这一点我很清楚,因为我自己就对各种宝宝(从完美到丑到爆的)都夸过可爱——所以这信息量也是零。顺便一提,我曾经画过一组图,描绘朋友去拜访一个&quot;不太可爱&quot;的宝宝的家长时会发生什么:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/16.1_friends.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/16.2_friends.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/16.3_friends.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/16.4_friends.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/16.5_friends.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><h3 id="_8-我是个运动技能大师" tabindex="-1">8) 我是个运动技能大师 <a class="header-anchor" href="#_8-我是个运动技能大师" aria-label="Permalink to &quot;8) 我是个运动技能大师&quot;">​</a></h3><p>宝宝什么都做不好,这一点还挺神奇的。他们不会思考,啥也不懂,身上所有部位都不会动。有意思的是,天天和一个各方面都超级不行的宝宝待在一起,反而让我对自己刮目相看。比如我看着宝宝坐在<a href="https://cdn.shopify.com/s/files/1/0057/9797/0008/products/Babybjorn-Toy-Bar-Image-2_1400x.jpg?v=1556318117" target="_blank" rel="noreferrer">婴儿摇椅</a>上,试图去够面前一英尺远的一朵小木头花,她的胳膊只是朝那个大致方向一挥,差得十万八千里。然后我伸手去拿一杯水,我全身的关节协同工作,把手沿着一条完美的直线送过三维空间,优雅地用刚刚好的力度握住杯子,举到嘴边,配合嘴唇的动作完美同步倾斜,然后把杯子放回桌上,轻轻搁下,像个绝对的天才。</p><h3 id="_9-你不会一夜之间从非父母变成父母" tabindex="-1">9) 你不会一夜之间从非父母变成父母 <a class="header-anchor" href="#_9-你不会一夜之间从非父母变成父母" aria-label="Permalink to &quot;9) 你不会一夜之间从非父母变成父母&quot;">​</a></h3><p>有些事就是太大了,我们人类的小脑袋瓜实在装不下。宇宙的浩瀚。死亡的永恒。<a href="https://waitbutwhy.com/2016/09/marriage-decision.html" target="_blank" rel="noreferrer">结婚这个决定</a>的重大程度——我<a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">曾经这样描述过</a>它:</p><p><em>当你选择一个人生伴侣,你实际上是在选一大堆东西,包括你的育儿搭档和一个会深刻影响你孩子的人、你大约 2 万顿饭的饭搭子、大约 100 次假期的旅伴、你主要的休闲时光和退休后的朋友、你的职业心理咨询师、以及一个你会听他讲 1.8 万次&quot;今天怎么样&quot;的人。狠活儿啊。</em></p><p>当爸爸几个月下来,我觉得这件事也属于那一类。你的宝宝一出生,你(希望如此)就再也不会作为一个非父母度过任何一天了。对于做出这个决定的人来说,这就是他们人生的公元前和公元后的分界线。这并不意味着你不能继续做你自己,但你确实是在用一种生活换另一种生活,连带着所有的好处和坏处。</p><p>我觉得我还没能完全消化这件事的重大程度。前几天一个好奇的没孩子的朋友问我,是不是觉得自己像个爸爸了,我自己都很意外地回答“不太像”。我大部分时候感觉还是原来的我,只不过我家里多了这个让人心花怒放的小东西。当我看到朋友带着已经有意识的孩子真正地在“为人父母”,说着“这样不好,别这样”之类的话,那种状态对我来说和三个月前一样神秘。至少对我来说,似乎为人父母是随着你的第一个宝宝慢慢变成一个人,而你自己也慢慢变成的一种东西。</p><p>顺便说一下,现在我比以前更加确信,这是最个人的个人决定,任何人都不应该去给别人施压让他们生孩子——这事儿太大了,轮不到别人来管。</p><h3 id="_10-有了宝宝真的会让你思考未来" tabindex="-1">10) 有了宝宝真的会让你思考未来 <a class="header-anchor" href="#_10-有了宝宝真的会让你思考未来" aria-label="Permalink to &quot;10) 有了宝宝真的会让你思考未来&quot;">​</a></h3><p>历史上每一位父母都是把宝宝带到一个未来不确定的世界里。但我们的未来是最不确定的。我的宝宝也许会过着和我很像的一生,只是稍微更未来主义一点。也许她会活到 500 岁。也许她这辈子大部分时间脑袋里都植入了<a href="https://waitbutwhy.com/2017/04/neuralink.html" target="_blank" rel="noreferrer">脑机接口</a>,用她自己的超级智能 AI 来思考。也许她会亲身经历文明崩溃。也许她生活的那个世界在我们今天看来就是乌托邦。也许她会住在火星上。也许她会遇到外星人。也许她会死于末日灾难。就是没法知道。这让所有那些关于未来的有趣、令人兴奋、令人恐惧的对话都更让人揪心一点。</p><h2 id="-1" tabindex="-1"><a href="https://waitbutwhy.com/wp-content/uploads/2023/05/17_stars.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a> <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;[![](/images/baby/17_stars.png)](https://waitbutwhy.com/wp-content/uploads/2023/05/17_stars.png)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章一发布我们就会发给你。</p><h2 id="要支持-wait-but-why-请访问我们的-patreon-页面-。" tabindex="-1">要支持 Wait But Why,请访问我们的**<a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a>**。 <a class="header-anchor" href="#要支持-wait-but-why-请访问我们的-patreon-页面-。" aria-label="Permalink to &quot;要支持 Wait But Why,请访问我们的**[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>更多配漫画的碎碎念:</strong><br><a href="https://waitbutwhy.com/2014/12/10-types-odd-friendships-youre-probably-part.html" target="_blank" rel="noreferrer">你多半也身处其中的 10 种奇葩友谊</a><br><a href="https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html" target="_blank" rel="noreferrer">社交互动的重重危险</a><br><a href="///Users/alicia/Dropbox/Shared%20with%20Alicia/Baby%2010%20weeks/11%20Awkward%20Things%20About%20Email" target="_blank" rel="noreferrer">关于邮件的 11 件尴尬事</a></p><p><strong>如果你正在纠结要不要和你的另一半结婚:</strong><a href="https://waitbutwhy.com/2016/09/marriage-decision.html" target="_blank" rel="noreferrer">结婚决定:永远拥有一切,或者永远失去一切</a></p><p><strong>如果你听到人人都在聊 AI,想要一个整体了解:</strong> <a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AI 革命:通往超级智能之路</a></p><hr><ol><li><p>头几个星期里我一直在琢磨一件事:爱因斯坦、希特勒、大鲨鱼奥尼尔 (Shaq)、柏拉图、伊丽莎白女王,他们曾经全都是扭来扭去、手脚乱挥的小外星人,这真的太奇怪了。<a href="#note-1-10203">↩</a></p></li><li><p>说到这个,那些生产按扣式(而不是拉链式)连体衣的公司,应该统统被送去劳改营。<a href="#note-2-10203">↩</a></p></li></ol><hr><ol><li>来源:<a href="https://www.reddit.com/r/dataisbeautiful/comments/e1kg7t/visualization_of_sleeping_patterns_in_a_newborns/" target="_blank" rel="noreferrer">图 1</a>、<a href="https://www.reddit.com/r/dataisbeautiful/comments/6s0ba9/months_3_to_17_of_my_babys_sleep_and/" target="_blank" rel="noreferrer">图 2</a>、<a href="https://www.babysleepsite.com/baby-sleep-patterns/baby-sleep-pattern-chart/" target="_blank" rel="noreferrer">图 3</a><a href="#note2-1-10203">↩</a></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">推特</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2023/05/baby.html&amp;description=10%20Thoughts%20from%20the%20Fourth%20Trimester" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p>',93)])])}const D=a(B,[["render",S]]);export{C as __pageData,D as default};
